import json, os

PATH = os.path.join(os.path.dirname(os.path.abspath(__file__)), "content_data", "anatomy_lessons.json")

def make_q(qt, opts, exp):
    options = []
    for o in opts:
        correct = o.startswith("*")
        options.append({"text": o.lstrip("*"), "is_correct": correct, "data_i18n": None})
    return {"question_text": qt, "attempted": 2, "data_i18n": None, "options": options, "explanation": exp}

def make_fc(term, defn):
    return {"question": term, "answer": defn, "data_i18n_q": None, "data_i18n_a": None}

